// AO 프롬프트 조립기 — Last-Edit Priority + Prompt Lock (재생성 연결)
const job = $input.first().json;

// mark-processing RETURNING * 에서 최신 DB 값이 이미 전달됨
const p1 = (job.prompt_p1 || '').trim();

// files 파싱
let files = [];
try {
  files = typeof job.clips === 'string' ? JSON.parse(job.clips) : (job.clips || []);
} catch(e) { files = []; }

// FNV-1a 해시 함수
function fnvHash(text) {
  let h = 0x811c9dc5;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  const hex = (h >>> 0).toString(16).padStart(8, '0');
  return hex + '-' + text.length + '-' + text.substring(0, 4).split('').map(c => c.charCodeAt(0).toString(16)).join('');
}

// Prompt Lock: prompt_hash 비교
const storedHash = job.prompt_hash || '';
const currentHash = p1 ? fnvHash(p1) : '';
const promptLockValid = !storedHash || storedHash === currentHash;

// Prompt Lock 불일치 시: 최신 prompt_p1 기준으로 재생성
// mark-processing RETURNING * 에서 이미 최신 DB 값이므로 현재 p1이 최신
// 저장된 해시만 현재 해시로 갱신 (DB UPDATE는 아래 플래그로 후속 처리)
let promptHashToUse = storedHash;
let promptLockAction = 'none';
if (!promptLockValid && p1) {
  // 기존 계획 폐기 → 현재 prompt_p1 기준으로 재조립
  promptHashToUse = currentHash;
  promptLockAction = 'regenerated';
}

// Last-Edit Priority: prompt_p1을 그대로 사용 (슬롯 치환 없음)
const finalPrompt = p1;

// 파일 분석 결과 수집
const analysisParts = [];
files.forEach((f, i) => {
  if (f.vision_analysis) analysisParts.push(`[Image ${i+1}: ${f.vision_analysis}]`);
  if (f.video_analysis) analysisParts.push(`[Video ${i+1}: ${f.video_analysis}]`);
});

// P1이 없으면 topic 기반 자동 프롬프트 (fallback)
let basePrompt = finalPrompt;
if (!p1) {
  const autoParts = [];
  if (job.topic) autoParts.push(`Create a cinematic video about: ${job.topic}`);
  if (job.keywords) autoParts.push(`Keywords: ${job.keywords}`);
  if (job.category) autoParts.push(`Category: ${job.category}`);
  basePrompt = autoParts.join('. ') + '. High quality, smooth motion, professional cinematography.';
}

const promptWithAnalysis = analysisParts.length > 0
  ? analysisParts.join('\n') + '\n' + basePrompt
  : basePrompt;

// generated_images 파싱
let generatedImages = [];
try {
  generatedImages = typeof job.generated_images === 'string' ? JSON.parse(job.generated_images) : (job.generated_images || []);
} catch(e) { generatedImages = []; }

// Length Gate: target_duration 설정
const targetDuration = job.duration || null;
const maxDuration = targetDuration ? targetDuration + 1 : null;
const strictMode = job.strict_mode === true;
const verifyMode = job.verify_mode === true;

// Prompt Lock 불일치 시 prompt_hash 갱신 (DB UPDATE)
if (promptLockAction === 'regenerated') {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://76.13.182.180:8080/v1/toolkit/echo',
      headers: { 'Content-Type': 'application/json' },
      body: { message: `prompt_lock_regenerated: job=${job.id}, old=${storedHash}, new=${currentHash}` },
      json: true,
      timeout: 5000
    });
  } catch(e) { /* 로깅 실패 무시 */ }
}

// metadata에서 scenes 추출 (Producer가 metadata JSONB에 저장)
const metadata = typeof job.metadata === 'string' ? JSON.parse(job.metadata) : (job.metadata || {});
const scenes = metadata.scenes || job.scenes || [];

return [{
  json: {
    ...job,
    files: files,
    scenes: scenes,
    generated_images: generatedImages,
    clip_duration: (job.clip_duration === 0 || job.clip_duration === '0' || String(job.clip_duration || '').toLowerCase() === 'auto') ? 'auto' : (parseInt(job.clip_duration) || 8),
    clip_duration_mode: (targetDuration && targetDuration > 15 && (!job.clip_duration || parseInt(job.clip_duration) === 8)) ? 'auto' : 'fixed',
    prompt_to_engine: promptWithAnalysis,
    prompt_p1_preserved: p1 || null,
    prompt_auto_generated: !p1,
    prompt_lock_valid: promptLockValid,
    prompt_lock_action: promptLockAction,
    prompt_hash_current: currentHash,
    prompt_hash: promptHashToUse,
    target_duration: targetDuration,
    max_duration: maxDuration,
    strict_mode: strictMode,
    verify_mode: verifyMode,
    assembled_at: new Date().toISOString()
  }
}];

// 한글→영문 번역 (Claude API)
const job = $input.first().json;
const claudeKey = $env.CLAUDE_API_KEY;
if (!claudeKey) throw new Error('CLAUDE_API_KEY 환경변수 없음');

const prompt = job.prompt_to_engine || '';
const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': claudeKey,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
  },
  body: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1000,
    messages: [{
      role: 'user',
      content: '다음 한국어 텍스트를 영어로 번역해줘. 원문 의미를 100% 보존하고, 번역문만 반환해. 설명 없이.\n\n' + prompt
    }]
  },
  json: true
});

return [{ json: resp }];

const prev = $('번역 필요 여부').first().json;
const translated = $input.first().json;

const promptEn = translated.content?.[0]?.text || prev.prompt_to_engine;

return [{
  json: {
    ...prev,
    prompt_en: promptEn
  }
}];

// NCA FFmpeg 합성 — slideshow / ai_video 모두 NCA 사용

function ensureExtension(url, ext) {
  if (!url) return url;
  const qIdx = url.indexOf('?');
  const path = qIdx >= 0 ? url.substring(0, qIdx) : url;
  if (/\.(jpg|jpeg|png|gif|webp|mp4|mp3|wav|m4a)$/i.test(path)) return url;
  return url + (url.includes('?') ? '&' : '?') + 'ext=.' + ext;
}
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
const ar = job.aspect_ratio || '9:16';
const W = ar === '16:9' ? 1920 : 1080;
const H = ar === '16:9' ? 1080 : 1920;
const DEFAULT_BGM = 'http://76.13.182.180:9000/audio/bgm_new.mp3';
const SFX_URL = 'http://76.13.182.180:9000/audio/sfx_ppook.wav';
// bgm_mode / sfx_mode 기반 (하위 호환 fallback 포함)
const bgmMode = job.bgm_mode || (job.enable_bgm === true ? 'ai_auto' : 'none');
const sfxMode = job.sfx_mode || (job.enable_sfx === true ? 'ai_auto' : 'none');
const enableBgm = bgmMode === 'ai_auto' || (bgmMode === 'uploaded' && !!job.bgm_url);
const enableSfx = sfxMode !== 'none';
const bgmUrl = job.bgm_url || (bgmMode === 'uploaded' ? '' : DEFAULT_BGM);
const sfxFileUrl = job.sfx_file_url || '';
const SFX_ACTIVE_URL = (sfxMode === 'uploaded' || sfxMode === 'combined') && sfxFileUrl ? sfxFileUrl : SFX_URL;

function escSingle(t) {
  if (!t) return '';
  return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
    .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
    .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
    .replace(/\[/g,'\\[').replace(/\]/g,'\\]').replace(/\n/g,' ');
}
function escMulti(t) {
  if (!t) return '';
  return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
    .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
    .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
    .replace(/\[/g,'\\[').replace(/\]/g,'\\]');
}
function wrap(t, max) {
  if (!t || t.replace(/\s+/g,'').length <= max) return t || '';
  const mid = Math.floor(t.length / 2);
  let best = -1, minD = t.length;
  for (let i = 1; i < t.length - 1; i++) {
    if (t[i] === ' ' && Math.abs(i - mid) < minD) { minD = Math.abs(i - mid); best = i; }
  }
  if (best > 0) return t.substring(0, best).trim() + '\n' + t.substring(best).trim();
  return t.substring(0, max) + '\n' + t.substring(max);
}
function wrapTitle(t, max) {
  if (!t || t.length <= max) return t || '';
  const mid = Math.floor(t.length / 2);
  let best = -1, minD = t.length;
  for (let i = 0; i < t.length; i++) {
    if (t[i] === ',' && Math.abs(i+1-mid) < minD) { minD = Math.abs(i+1-mid); best = i+1; }
  }
  if (best === -1) {
    for (let i = 1; i < t.length-1; i++) {
      if (t[i] === ' ' && Math.abs(i-mid) < minD) { minD = Math.abs(i-mid); best = i; }
    }
  }
  if (best > 0) return t.substring(0, best).trim() + '\n' + t.substring(best).trim();
  return t.substring(0, max) + '\n' + t.substring(max);
}

const subtitles = job.tts_subtitles || [];
const audioUrl = job.tts_audio_url;
const totalDuration = job.total_duration || 10;
const topicText = escMulti(wrapTitle(job.topic || '', 14));

let inputs = [];
let idx = 0;

if (productionMode === 'slideshow') {
  // ===== SLIDESHOW =====
  const imgUrls = job.slide_image_urls || [];
  if (imgUrls.length === 0) throw new Error('slideshow: 이미지 없음');
  const imgDur = job.img_duration || (totalDuration / imgUrls.length);

  for (const url of imgUrls) {
    inputs.push({ file_url: ensureExtension(url, 'jpg'), options: [
      { option: '-loop', argument: '1' },
      { option: '-framerate', argument: '30' },
      { option: '-t', argument: imgDur.toFixed(2) }
    ] });
    idx++;
  }

  // TTS
  const audioIdx = idx;
  if (audioUrl) { inputs.push({ file_url: ensureExtension(audioUrl, 'mp3'), options: [] }); idx++; }

  // BGM (enableBgm일 때만)
  let bgmIdx = -1;
  if (enableBgm) {
    bgmIdx = idx;
    inputs.push({ file_url: ensureExtension(bgmUrl, 'mp3'), options: [{ option: '-stream_loop', argument: '-1' }] }); idx++;
  }

  // SFX (enableSfx일 때만, 이미지 전환)
  const sfxList = [];
  if (enableSfx) {
    for (let i = 1; i < imgUrls.length; i++) {
      inputs.push({ file_url: SFX_ACTIVE_URL, options: [] });
      sfxList.push({ idx: idx, ms: Math.round(i * imgDur * 1000) }); idx++;
    }
  }

  let fp = [];
  // 이미지: 풀프레임 확대 crop (패딩 없음)
  for (let i = 0; i < imgUrls.length; i++) {
    if (ar === '16:9') {
      fp.push(`[${i}:v]scale=${W}:${H}:force_original_aspect_ratio=increase,crop=${W}:${H},setsar=1,fps=30[v${i}]`);
    } else {
      fp.push(`[${i}:v]scale=1080:1080:force_original_aspect_ratio=increase,crop=1080:1080,setsar=1,fps=30[v${i}]`);
    }
  }
  fp.push(`${imgUrls.map((_,i) => `[v${i}]`).join('')}concat=n=${imgUrls.length}:v=1:a=0[vconcat]`);

  // 오디오 믹싱 (조건부)
  if (audioUrl) fp.push(`[${audioIdx}:a]atrim=duration=${totalDuration.toFixed(2)},asetpts=PTS-STARTPTS[tts_raw]`);

  if (enableBgm && bgmIdx >= 0) {
    const bgmTotalDur = totalDuration + 2;
    fp.push(`[${bgmIdx}:a]atrim=duration=${bgmTotalDur.toFixed(2)},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, totalDuration - 2).toFixed(2)}:d=2[bgm]`);
  }

  if (enableSfx && sfxList.length > 0) {
    sfxList.forEach((s, i) => fp.push(`[${s.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=${s.ms}|${s.ms}[sfx${i}]`));
    fp.push(`${sfxList.map((_,i) => `[sfx${i}]`).join('')}amix=inputs=${sfxList.length}:duration=longest:normalize=0[sfx_mix]`);
  }

  // 최종 오디오 조합
  if (audioUrl && enableBgm && enableSfx && sfxList.length > 0) {
    fp.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
  } else if (audioUrl && enableBgm) {
    fp.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
  } else if (audioUrl && enableSfx && sfxList.length > 0) {
    fp.push(`[tts_raw][sfx_mix]amix=inputs=2:duration=longest:weights=1 0.8:normalize=0[amain]`);
  } else if (audioUrl) {
    fp.push(`[tts_raw]acopy[amain]`);
  } else if (enableBgm) {
    fp.push(`[bgm]acopy[amain]`);
  } else {
    fp.push(`anullsrc=r=44100:cl=stereo,atrim=duration=${totalDuration.toFixed(2)}[amain]`);
  }

  // 상단 제목 + 하단 자막
  let ov = `[vconcat]drawbox=y=40:w=${W}:h=280:color=#000000@1.0:t=fill`;
  if (topicText) {
    ov += `,drawtext=expansion=none:text='${topicText}':fontsize=72:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=120:line_spacing=12`;
  }
  for (const sub of subtitles) {
    const st = escMulti(wrap(sub.text, 12));
    if (!st) continue;
    ov += `,drawtext=expansion=none:text='${st}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:line_spacing=8:borderw=4:bordercolor=black:enable='between(t\\,${sub.start.toFixed(2)}\\,${(sub.start + sub.duration).toFixed(2)})'`;
  }
  ov += '[vfinal]';
  fp.push(ov);

  const payload = {
    inputs,
    filters: [{ filter: fp.join(';') }],
    outputs: [{ options: [
      { option: '-map', argument: '[vfinal]' }, { option: '-map', argument: '[amain]' },
      { option: '-c:v', argument: 'libx264' }, { option: '-preset', argument: 'fast' }, { option: '-crf', argument: '23' },
      { option: '-c:a', argument: 'aac' }, { option: '-b:a', argument: '192k' },
      { option: '-pix_fmt', argument: 'yuv420p' }, { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: totalDuration.toFixed(2) }
    ], file_name: 'ao_slideshow.mp4' }]
  };

  const ncaResp = await this.helpers.httpRequest({
    method: 'POST', url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
    body: payload, json: true, timeout: 600000
  });

  let videoUrl = '';
  if (Array.isArray(ncaResp.response)) videoUrl = ncaResp.response[0]?.file_url || '';
  else if (typeof ncaResp.response === 'string') videoUrl = ncaResp.response;
  else videoUrl = ncaResp.output_url || ncaResp.url || ncaResp.video_url || '';
  if (!videoUrl) throw new Error('NCA 슬라이드쇼 URL 없음: ' + JSON.stringify(ncaResp).substring(0, 500));

  return [{ json: { id: 'nca-slideshow', status: 'succeeded', url: videoUrl } }];

} else {
  // ===== AI_VIDEO =====
  const klingVideoUrls = job.kling_video_urls || (job.kling_video_url ? [job.kling_video_url] : []);
  if (klingVideoUrls.length === 0) throw new Error('ai_video: kling_video_url(s) 없음');
  const videoDuration = job.total_duration || parseInt(job.clip_duration) || 8;
  const isMultiClip = klingVideoUrls.length > 1;

  // 영상 클립 입력
  const videoStartIdx = idx;
  for (const vUrl of klingVideoUrls) {
    inputs.push({ file_url: ensureExtension(vUrl, 'mp4'), options: [] }); idx++;
  }

  const audioIdx = idx;
  if (audioUrl) { inputs.push({ file_url: ensureExtension(audioUrl, 'mp3'), options: [] }); idx++; }

  let bgmIdx = -1;
  if (enableBgm) {
    bgmIdx = idx;
    inputs.push({ file_url: ensureExtension(bgmUrl, 'mp3'), options: [{ option: '-stream_loop', argument: '-1' }] }); idx++;
  }

  // F-9: 동적 SFX 타이밍 (sfx_timings 배열 사용)
  const sfxTimings = job.sfx_timings || [];
  const sfxIndices = [];
  if (enableSfx && sfxTimings.length > 0) {
    for (const st of sfxTimings) {
      sfxIndices.push({ idx: idx, ms: Math.round(st.start * 1000) });
      inputs.push({ file_url: SFX_ACTIVE_URL, options: [] }); idx++;
    }
  } else if (enableSfx) {
    // fallback: 단일 SFX at 500ms
    sfxIndices.push({ idx: idx, ms: 500 });
    inputs.push({ file_url: SFX_ACTIVE_URL, options: [] }); idx++;
  }

  let fp = [];
  // 영상: 풀프레임 확대 crop — 멀티클립 concat 대응
  if (isMultiClip) {
    for (let vi = 0; vi < klingVideoUrls.length; vi++) {
      fp.push(`[${videoStartIdx + vi}:v]scale=${W}:${H}:force_original_aspect_ratio=increase,crop=${W}:${H},setsar=1,fps=30[v${vi}]`);
    }
    fp.push(`${klingVideoUrls.map((_, i) => `[v${i}]`).join('')}concat=n=${klingVideoUrls.length}:v=1:a=0[vscaled]`);
  } else {
    fp.push(`[${videoStartIdx}:v]scale=${W}:${H}:force_original_aspect_ratio=increase,crop=${W}:${H},setsar=1,fps=30[vscaled]`);
  }

  if (audioUrl) fp.push(`[${audioIdx}:a]atrim=duration=${totalDuration.toFixed(2)},asetpts=PTS-STARTPTS[tts_raw]`);

  if (enableBgm && bgmIdx >= 0) {
    const bgmTotalDur = totalDuration + 2;
    fp.push(`[${bgmIdx}:a]atrim=duration=${bgmTotalDur.toFixed(2)},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, totalDuration - 2).toFixed(2)}:d=2[bgm]`);
  }

  // F-9: 동적 SFX 필터 (각 타이밍에 adelay 적용)
  if (enableSfx && sfxIndices.length > 0) {
    sfxIndices.forEach((s, i) => fp.push(`[${s.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=${s.ms}|${s.ms}[sfx${i}]`));
    if (sfxIndices.length > 1) {
      fp.push(`${sfxIndices.map((_,i) => `[sfx${i}]`).join('')}amix=inputs=${sfxIndices.length}:duration=longest:normalize=0[sfx_mix]`);
    } else {
      fp.push(`[sfx0]acopy[sfx_mix]`);
    }
  }

  // 오디오 조합
  const hasSfx = enableSfx && sfxIndices.length > 0;
  if (audioUrl && enableBgm && hasSfx) {
    fp.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
  } else if (audioUrl && enableBgm) {
    fp.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
  } else if (audioUrl && hasSfx) {
    fp.push(`[tts_raw][sfx_mix]amix=inputs=2:duration=longest:weights=1 0.8:normalize=0[amain]`);
  } else if (audioUrl) {
    fp.push(`[tts_raw]acopy[amain]`);
  } else if (enableBgm) {
    fp.push(`[bgm]acopy[amain]`);
  } else {
    fp.push(`anullsrc=r=44100:cl=stereo,atrim=duration=${totalDuration.toFixed(2)}[amain]`);
  }

  // 상단 제목 + 하단 자막
  let ov = `[vscaled]drawbox=y=40:w=${W}:h=280:color=#000000@1.0:t=fill`;
  if (topicText) {
    ov += `,drawtext=expansion=none:text='${topicText}':fontsize=72:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=120:line_spacing=12`;
  }
  for (const sub of subtitles) {
    const st = escMulti(wrap(sub.text, 12));
    if (!st) continue;
    ov += `,drawtext=expansion=none:text='${st}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:line_spacing=8:borderw=4:bordercolor=black:enable='between(t\\,${sub.start.toFixed(2)}\\,${(sub.start + sub.duration).toFixed(2)})'`;
  }
  ov += '[vfinal]';
  fp.push(ov);

  const payload = {
    inputs,
    filters: [{ filter: fp.join(';') }],
    outputs: [{ options: [
      { option: '-map', argument: '[vfinal]' }, { option: '-map', argument: '[amain]' },
      { option: '-c:v', argument: 'libx264' }, { option: '-preset', argument: 'fast' }, { option: '-crf', argument: '23' },
      { option: '-c:a', argument: 'aac' }, { option: '-b:a', argument: '192k' },
      { option: '-pix_fmt', argument: 'yuv420p' }, { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: totalDuration.toFixed(2) }
    ], file_name: 'ao_video.mp4' }]
  };

  const ncaResp = await this.helpers.httpRequest({
    method: 'POST', url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
    body: payload, json: true, timeout: 600000
  });

  let videoUrl = '';
  if (Array.isArray(ncaResp.response)) videoUrl = ncaResp.response[0]?.file_url || '';
  else if (typeof ncaResp.response === 'string') videoUrl = ncaResp.response;
