}

// Claude 나레이션 스크립트 생성
async function generateNarration(rawText, job) {
  if (!rawText) return rawText;
  const claudeKey = $env.CLAUDE_API_KEY;
  if (!claudeKey) return rawText;
  try {
    // SPEC 4조: topic/keywords/category는 나레이션 생성에 영향 금지
    // prompt_p1만 소스로 사용
    const context = rawText;

    // narration_style + narration_tone
    const style = job.narration_style || '설명형';
    const tone = job.narration_tone || '차분하게';
    const styleGuide = `스타일: ${style}, 톤: ${tone}`;

    // target_duration 기반 분량 계산 (한국어 TTS 약 4.5자/초)
    const targetDur = job.target_duration || job.duration || null;
    let lengthGuide = '30초~1분 분량 (150~300자)';
    if (targetDur) {
      const targetChars = Math.round(targetDur * 4.5);
      const minChars = Math.round(targetChars * 0.85);
      const maxChars = Math.round(targetChars * 1.0);
      lengthGuide = `정확히 약 ${targetDur}초 분량 (${minChars}~${maxChars}자). 이 글자수를 반드시 맞춰줘`;
    }

    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': claudeKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 2048,
        messages: [{
          role: 'user',
          content: `다음 내용을 기반으로 영상 나레이션 스크립트를 작성해줘.\n- ${styleGuide}\n- 한국어 자연스러운 구어체\n- 시청자 관심을 끄는 도입부\n- ${lengthGuide}\n- 나레이션 텍스트만 출력 (설명/마크다운/제목 금지)\n\n${context}`
        }]
      },
      json: true
    });
    const narration = resp?.content?.[0]?.text;
    return narration && narration.trim().length > 10 ? narration.trim() : rawText;
  } catch (e) {
    return rawText;
  }
}

// kie.ai TTS 생성 (ElevenLabs multilingual v2) — 429 재시도 포함
async function generateTTS(text) {
  if (!text) return { audioUrl: null, duration: 0 };
  let audioUrl = null;
  for (let attempt = 0; attempt < 3; attempt++) {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.kie.ai/api/v1/jobs/createTask',
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: {
        model: 'elevenlabs/text-to-speech-multilingual-v2',
        input: { text: text, voice_id: 'EXAVITQu4vr4xnSDxMaL' }
      },
      json: true
    });
    const taskId = resp?.data?.taskId;
    if (!taskId) throw new Error('TTS taskId 없음');
    try {
      audioUrl = await pollTask.call(this, taskId);
      break;
    } catch(e) {
      if (attempt < 2 && (e.message.includes('internal error') || e.message.includes('429'))) {
        await new Promise(r => setTimeout(r, 30000 * (attempt + 1)));
        continue;
      }
      throw e;
    }
  }
  // ffprobe로 실제 오디오 길이 측정
  let actualDuration = 0;
  if (audioUrl) {
    try {
      const probeResp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://76.13.182.180:8080/v1/toolkit/ffprobe',
        headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
        body: { file_url: audioUrl },
        json: true,
        timeout: 30000
      });
      const streams = probeResp?.streams || probeResp?.format || {};
      actualDuration = parseFloat(probeResp?.format?.duration || streams?.duration || '0');
    } catch(e) { /* ffprobe 실패 시 추정값 사용 */ }
  }
  const estimatedDuration = Math.max(3, text.replace(/\s+/g, '').length / 4.5);
  const duration = actualDuration > 0 ? actualDuration : estimatedDuration;
  return { audioUrl, duration };
}

// F-10: AI 장면-이미지 자동 매칭
async function matchImageToScene(images, files, promptP1, narrationText) {
  if (!images || images.length < 2) return images;
  const claudeKey = $env.CLAUDE_API_KEY;
  if (!claudeKey) return images;

  // files에서 vision_analysis 추출
  const analyses = [];
  for (let i = 0; i < images.length; i++) {
    const matchFile = Array.isArray(files) ? files.find(f => f.url === images[i]) : null;
    analyses.push({
      index: i,
      url: images[i],
      analysis: matchFile?.vision_analysis || matchFile?.auto_prompt || `이미지 ${i + 1}`
    });
  }

  try {
    const analysisStr = analyses.map(a => `[${a.index}] ${a.analysis}`).join('\n');
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': claudeKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 512,
        messages: [{
          role: 'user',
          content: `영상 프롬프트와 나레이션 흐름에 맞게 이미지 순서를 재배치해줘.

프롬프트: ${promptP1 || ''}
나레이션: ${narrationText || ''}

이미지 목록 (현재 순서):
${analysisStr}

규칙:
- 나레이션/프롬프트의 서사 흐름에 맞는 순서로 재배치
- 도입부에 어울리는 이미지를 먼저, 클라이맥스/결론에 어울리는 이미지를 나중에
- 원본 index 번호의 배열로만 응답해. 다른 텍스트 금지

예시 응답: [2, 0, 1, 3]`
        }]
      },
      json: true
    });

    const raw = (resp?.content?.[0]?.text || '').trim();
    const jsonStr = raw.replace(/^\`\`\`json?\n?/i, '').replace(/\n?\`\`\`$/i, '').trim();
    const order = JSON.parse(jsonStr);

    if (Array.isArray(order) && order.length === images.length) {
      const valid = order.every(i => typeof i === 'number' && i >= 0 && i < images.length);
      const unique = new Set(order).size === order.length;
      if (valid && unique) {
        return order.map(i => images[i]);
      }
    }
    return images;
  } catch(e) {
    return images;
  }
}

// use_mode별 이미지 처리 (direct / analysis_only)
async function processFilesByUseMode(fileList) {
  const imageUrls = [];
  for (const f of fileList) {
    if (f.type !== 'image') continue;
    const mode = f.use_mode || 'direct';
    if (mode === 'direct') {
      if (f.url) imageUrls.push(f.url);
    } else if (mode === 'analysis_only') {
      const prompt = f.auto_prompt || f.vision_analysis || 'Cinematic image, high quality.';
      const url = await generateImage.call(this, prompt);
      if (url) imageUrls.push(url);
    }
  }
  return imageUrls;
}

// 자막 타이밍 배치 (Claude API) + fallback (글자수 비율)
async function buildSubtitleTimings(promptP1, narrationText, targetDuration) {
  const result = { scene_duration: targetDuration, subtitle_timings: [] };
  if (!narrationText || !narrationText.trim()) return result;

  // fallback: 글자수 비율 배분
  function fallbackTimings(text, dur) {
    const sentences = text.split(/(?<=[.!?\u3002\uFF01\uFF1F])\s*/).filter(s => s.trim());
    if (sentences.length === 0) return [];
    const totalChars = sentences.reduce((sum, s) => sum + s.replace(/\s+/g, '').length, 0);
    let offset = 0;
    return sentences.map(s => {
      const chars = s.replace(/\s+/g, '').length;
      const d = totalChars > 0 ? (chars / totalChars) * dur : dur / sentences.length;
      const seg = { text: s.trim(), start: parseFloat(offset.toFixed(2)), duration: parseFloat(d.toFixed(2)) };
      offset += d;
      return seg;
    });
  }

  const claudeKey = $env.CLAUDE_API_KEY;
  if (!claudeKey) {
    result.subtitle_timings = fallbackTimings(narrationText, targetDuration);
    result.scene_duration = targetDuration;
    return result;
  }

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': claudeKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 2048,
        messages: [{
          role: 'user',
          content: `나레이션 텍스트를 자막 구간으로 분리하고 타이밍을 배정해줘.

규칙:
- 자연스러운 호흡/문장 단위로 분리 (한 구간 최대 15자)
- 각 구간의 start(시작 초)와 duration(지속 초)을 배정
- 한국어 TTS 발화 속도 약 4.5자/초 기준
- 구간 사이에 0.2~0.5초 호흡 간격 포함
- 강조 구간은 duration을 약간 길게 (1.2배)
- 총 길이가 ${targetDuration}초에 맞도록 조절
- 마지막 구간 종료 시점 = scene_duration

나레이션:
${narrationText}

반드시 아래 JSON 형식으로만 응답해. 다른 텍스트 금지:
{"scene_duration": 숫자, "subtitle_timings": [{"text": "자막텍스트", "start": 0.0, "duration": 3.5}]}`
        }]
      },
      json: true
    });

    const raw = (resp?.content?.[0]?.text || '').trim();
    const jsonStr = raw.replace(/^```json?\n?/i, '').replace(/\n?```$/i, '').trim();
    const parsed = JSON.parse(jsonStr);

    if (parsed.subtitle_timings && Array.isArray(parsed.subtitle_timings) && parsed.subtitle_timings.length > 0) {
      result.subtitle_timings = parsed.subtitle_timings.map(t => ({
        text: String(t.text || ''),
        start: parseFloat(t.start) || 0,
        duration: parseFloat(t.duration) || 1
      }));
      const last = result.subtitle_timings[result.subtitle_timings.length - 1];
      result.scene_duration = parseFloat(parsed.scene_duration) || (last.start + last.duration);
    } else {
      result.subtitle_timings = fallbackTimings(narrationText, targetDuration);
    }
  } catch(e) {
    result.subtitle_timings = fallbackTimings(narrationText, targetDuration);
    result.scene_duration = targetDuration;
  }

  return result;
}


// F-9: AI 효과음 타이밍 생성 (Claude API)
async function generateSfxTimings(promptP1, subtitleTimings) {
  if (!subtitleTimings || subtitleTimings.length === 0) return [];
  const claudeKey = $env.CLAUDE_API_KEY;
  if (!claudeKey) return [];

  try {
    const timingsStr = subtitleTimings.map(t => `[${t.start.toFixed(1)}s~${(t.start+t.duration).toFixed(1)}s] ${t.text}`).join('\n');
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': claudeKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1024,
        messages: [{
          role: 'user',
          content: `영상 나레이션에 어울리는 효과음 타이밍을 결정해줘.

프롬프트: ${promptP1 || ''}

나레이션 타이밍:
${timingsStr}

규칙:
- 최대 5개 효과음 (너무 많으면 산만)
- 장면 전환, 강조, 등장 순간에 배치
- 나레이션과 겹치지 않는 호흡 구간(0.2~0.5초 갭)에 우선 배치
- start는 초 단위, duration은 0.2~0.5초
- description은 한국어로 간단하게

반드시 아래 JSON 배열로만 응답해. 다른 텍스트 금지:
[{"description": "효과음 설명", "start": 0.0, "duration": 0.3}]`
        }]
      },
      json: true
    });

    const raw = (resp?.content?.[0]?.text || '').trim();
    const jsonStr = raw.replace(/^\`\`\`json?\n?/i, '').replace(/\n?\`\`\`$/i, '').trim();
    const parsed = JSON.parse(jsonStr);

    if (Array.isArray(parsed)) {
      return parsed.slice(0, 5).map(s => ({
        description: String(s.description || ''),
        start: parseFloat(s.start) || 0,
        duration: parseFloat(s.duration) || 0.3
      }));
    }
    return [];
  } catch(e) {
    return [];
  }
}

// ===== SLIDESHOW 모드 =====
if (productionMode === 'slideshow') {
  // use_mode별 이미지 처리
  const processedImages = await processFilesByUseMode.call(this, files);
  // generated_images 합류
  let allImages = [...processedImages, ...generatedImages].filter(Boolean);
  if (allImages.length === 0) throw new Error('slideshow: 사용 가능한 이미지 없음');

  // 나레이션 텍스트
  let ttsText;
  if ((job.narration_script || job.narration_text) && (job.narration_script || job.narration_text).trim()) {
    ttsText = (job.narration_script || job.narration_text).trim();
  } else {
    const rawText = (job.prompt_p1 || job.topic || '').replace(/<[^>]*>?/gm, '');
    if (!rawText) throw new Error('slideshow: 나레이션 텍스트(prompt_p1 또는 topic) 없음');
    ttsText = await generateNarration.call(this, rawText, job);
  }

  // TTS 생성
  const tts = await generateTTS.call(this, ttsText);
  if (!tts.audioUrl) throw new Error('TTS 생성 실패');

  const audioDuration = tts.duration;
  const imgDuration = audioDuration / allImages.length;
  const timingResult = await buildSubtitleTimings.call(this, job.prompt_p1 || '', ttsText, audioDuration);
  const subtitles = timingResult.subtitle_timings;

  // === Length Gate (slideshow) ===
  const targetDuration = job.target_duration || job.duration || null;
  const maxDuration = targetDuration ? targetDuration + 1 : null;
  const strictMode = job.strict_mode === true;
  let lengthGateStatus = 'no_gate';
  let adjustedAudioDuration = audioDuration;

  if (targetDuration) {
    if (audioDuration <= maxDuration) {
      lengthGateStatus = 'pass';
    } else if (strictMode) {
      lengthGateStatus = 'blocked';
      throw new Error(`LENGTH_GATE_BLOCKED: ${audioDuration}s > max ${maxDuration}s (strict_mode)`);
    } else {
      lengthGateStatus = 'over_soft';
    }
  }

  // === Verify Mode: output_hash ===
  const verifyMode = job.verify_mode === true;
  let outputHash = null;
  if (verifyMode) {
    const hashInput = JSON.stringify({
      prompt_to_engine: job.prompt_to_engine || '',
      production_mode: 'slideshow',
      slide_count: allImages.length,
      aspect_ratio: job.aspect_ratio || '9:16',
      target_duration: targetDuration,
      tts_text: ttsText || '',
      total_duration: audioDuration
    });
    let oh = 0x811c9dc5;
    for (let i = 0; i < hashInput.length; i++) {
      oh ^= hashInput.charCodeAt(i);
      oh = Math.imul(oh, 0x01000193);
    }
    outputHash = (oh >>> 0).toString(16).padStart(8, '0');
  }

  return [{
    json: {
      ...job,
      production_mode: 'slideshow',
      slide_image_urls: allImages,
      tts_audio_url: tts.audioUrl,
      tts_duration: audioDuration,
      tts_text: ttsText,
      tts_subtitles: subtitles,
      img_duration: imgDuration,
      scene_results: allImages.map((url, i) => ({
        index: i, image_url: url, start: i * imgDuration, duration: imgDuration, type: 'slide'
      })),
      total_scenes: allImages.length,
      total_duration: audioDuration,
      bgm_mode: bgmMode,
      sfx_mode: sfxMode,
      bgm_url: job.bgm_url || '',
      sfx_file_url: sfxFileUrl,
      length_gate_status: lengthGateStatus,
      target_duration: targetDuration,
      max_duration: maxDuration,
      verify_mode: verifyMode,
      output_hash: outputHash
    }
  }];
}

