// generated_images 합류
const allImages = [...processedImages, ...generatedImages].filter(Boolean);

// clip_duration 자동/고정 판별
const clipDurMode = job.clip_duration_mode || 'fixed';
const isAutoClip = clipDurMode === 'auto' || String(job.clip_duration).toLowerCase() === 'auto';
const fixedClipDur = isAutoClip ? 8 : (parseInt(job.clip_duration) || 8);

// ① 나레이션 텍스트 (Kling 전에 준비 — auto 모드에서 TTS 길이 필요)
let ttsText;
if ((job.narration_script || job.narration_text) && (job.narration_script || job.narration_text).trim()) {
  ttsText = (job.narration_script || job.narration_text).trim();
} else {
  const rawText = (job.prompt_p1 || job.topic || '').replace(/<[^>]*>?/gm, '');
  ttsText = rawText ? await generateNarration.call(this, rawText, job) : '';
}

// F-10: image_order=auto → AI 장면-이미지 매칭 (나레이션 텍스트 확보 후)
if (imageOrder === 'auto' && allImages.length >= 2) {
  allImages = await matchImageToScene.call(this, allImages, files, job.prompt_p1 || '', ttsText || '');
}

// ② TTS 생성 + ffprobe (Kling 전에 실행)
const targetDur = job.target_duration || job.duration || null;
let tts = ttsText ? await generateTTS.call(this, ttsText) : { audioUrl: null, duration: fixedClipDur };

// Length Gate 보정: TTS가 목표보다 짧으면 나레이션 재생성 1회
const minAcceptable = job.strict_mode === true ? (targetDur - 1) : (targetDur - 3);
if (targetDur && tts.audioUrl && tts.duration < minAcceptable && !(job.narration_script || job.narration_text)) {
  const rawText = (job.prompt_p1 || job.topic || '').replace(/<[^>]*>?/gm, '');
  if (rawText) {
    const retryText = await generateNarration.call(this, rawText, { ...job, target_duration: targetDur });
    if (retryText && retryText.length > ttsText.length) {
      ttsText = retryText;
      tts = await generateTTS.call(this, ttsText);
    }
  }
}

// ③ clipDur + 멀티클립 계산 (scenes 대응)
const scenes = job.scenes || [];
const hasScenes = scenes.length > 0;
const targetLen = targetDur || (isAutoClip ? tts.duration : fixedClipDur);
const MAX_CLIP_SEC = 15;
const clipCount = hasScenes ? scenes.length : (targetLen > MAX_CLIP_SEC ? Math.ceil(targetLen / MAX_CLIP_SEC) : 1);
const perClipSec = hasScenes ? 0 : Math.max(3, Math.min(MAX_CLIP_SEC, Math.ceil(targetLen / clipCount)));
const clipDur = isAutoClip ? (tts.duration || targetLen) : (clipCount > 1 ? perClipSec : fixedClipDur);

// ④ Kling 영상 생성 (멀티클립 대응)
const skipKlingFile = Array.isArray(files) && files.find(f => f.skip_kling === true && f.url);
let videoUrls = [];

if (skipKlingFile) {
  videoUrls = [skipKlingFile.url];
} else {
  for (let ci = 0; ci < clipCount; ci++) {
    const scenePrompt = hasScenes ? (scenes[ci].prompt || promptBase) : promptBase;
    const sceneDurSec = hasScenes ? Math.max(3, Math.min(MAX_CLIP_SEC, parseInt(scenes[ci].duration_sec) || perClipSec)) : perClipSec;
    const klingDuration = String(Math.max(3, Math.min(MAX_CLIP_SEC, Math.ceil(sceneDurSec))));
    const klingInput = {
      prompt: scenePrompt,
      aspect_ratio: aspectRatio,
      mode: 'std',
      sound: false,
      duration: klingDuration,
      multi_shots: false
    };

    if (allImages.length > 0) {
      klingInput.image_urls = allImages.slice(0, 2);
    }

    let taskResp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.kie.ai/api/v1/jobs/createTask',
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: { model: 'kling-3.0/video', input: klingInput },
      json: true
    });

    // 이미지 URL 실패 시 처리 (direct 이미지는 유지)
    if (taskResp?.code !== 200 && klingInput.image_urls) {
      if (directImages.length > 0) {
        throw new Error('Kling image_urls 실패 (direct 이미지 포함): code=' + (taskResp?.code || 'unknown') + ', msg=' + JSON.stringify(taskResp?.message || taskResp?.msg || '').substring(0, 200));
      }
      delete klingInput.image_urls;
      taskResp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.kie.ai/api/v1/jobs/createTask',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: { model: 'kling-3.0/video', input: klingInput },
        json: true
      });
    }

    const klingTaskId = taskResp?.data?.taskId;
    if (!klingTaskId) throw new Error('Kling taskId 없음 (clip ' + ci + '): ' + JSON.stringify(taskResp).substring(0, 200));
    const url = await pollTask.call(this, klingTaskId);
    if (!url) throw new Error('Kling 영상 URL 없음 (clip ' + ci + ')');
    videoUrls.push(url);
  }
}

// ⑤ totalDuration 계산
const videoDuration = hasScenes ? scenes.reduce((s, sc) => s + Math.max(3, Math.min(MAX_CLIP_SEC, parseInt(sc.duration_sec) || 5)), 0) : perClipSec * clipCount;
let totalDuration = tts.audioUrl ? Math.max(videoDuration, tts.duration) : videoDuration;
let subtitles = [];
let sceneDuration = 0;
let totalDurationSource = 'tts';
if (ttsText) {
  const timingResult = await buildSubtitleTimings.call(this, job.prompt_p1 || '', ttsText, totalDuration);
  subtitles = timingResult.subtitle_timings;
  sceneDuration = timingResult.scene_duration || 0;
  // F-8: auto 모드 — TTS 실측 vs scene_duration 긴 쪽 기준
  if (isAutoClip && sceneDuration > 0) {
    if (sceneDuration > tts.duration) {
      totalDuration = sceneDuration;
      totalDurationSource = 'scene';
    } else {
      totalDuration = tts.duration;
      totalDurationSource = 'tts';
    }
  }
}

// F-9: AI 효과음 타이밍 생성 (ai_auto / combined만)
let sfxTimings = [];
if (subtitles.length > 0 && (sfxMode === 'ai_auto' || sfxMode === 'combined')) {
  sfxTimings = await generateSfxTimings.call(this, job.prompt_p1 || '', subtitles);
}

// === Length Gate ===
const targetDuration = job.target_duration || job.duration || null;
const strictMode = job.strict_mode === true;
let lengthGateStatus = 'no_gate';
let gateClipCount = 1;
let lengthGateLog = '';

if (targetDuration) {
  // 통과 기준: strict=target±1초, soft=target-3초 이상
  const maxDuration = strictMode ? targetDuration + 1 : targetDuration + 1;
  const minDuration = strictMode ? targetDuration - 1 : targetDuration - 3;

  if (totalDuration >= minDuration && totalDuration <= maxDuration) {
    lengthGateStatus = 'pass';
  } else if (totalDuration < minDuration) {
    // 너무 짧음 → clip_count 보정 (영상 클립 반복으로 채움)
    gateClipCount = Math.ceil(targetDuration / Math.max(totalDuration, 1));
    const adjustedDuration = totalDuration * gateClipCount;
    if (adjustedDuration >= minDuration) {
      lengthGateStatus = 'corrected_short';
      totalDuration = Math.min(adjustedDuration, targetDuration);
      lengthGateLog = `짧음 보정: ${gateClipCount}클립, ${adjustedDuration.toFixed(1)}s`;
    } else if (strictMode) {
      lengthGateStatus = 'blocked_short';
      throw new Error(`LENGTH_GATE_BLOCKED: ${totalDuration.toFixed(1)}s < min ${minDuration}s (strict_mode)`);
    } else {
      lengthGateStatus = 'under_soft';
      lengthGateLog = `목표 미달 soft: ${totalDuration.toFixed(1)}s < ${minDuration}s`;
    }
  } else {
    // 너무 김 → clip_count 재계산
    gateClipCount = Math.ceil(totalDuration / targetDuration);
    const adjustedDuration = totalDuration / gateClipCount;
    if (adjustedDuration <= maxDuration && adjustedDuration >= minDuration) {
      lengthGateStatus = 'corrected_long';
      totalDuration = adjustedDuration;
      lengthGateLog = `김 보정: ${gateClipCount}클립, ${adjustedDuration.toFixed(1)}s`;
    } else if (strictMode) {
      lengthGateStatus = 'blocked_long';
      throw new Error(`LENGTH_GATE_BLOCKED: ${totalDuration.toFixed(1)}s > max ${maxDuration}s (strict_mode)`);
    } else {
      lengthGateStatus = 'over_soft';
      lengthGateLog = `목표 초과 soft: ${totalDuration.toFixed(1)}s > ${maxDuration}s`;
    }
  }
}

// === Verify Mode: output_hash 생성 ===
const verifyMode = job.verify_mode === true;
let outputHash = null;
if (verifyMode) {
  const hashInput = JSON.stringify({
    prompt_to_engine: job.prompt_to_engine || '',
    production_mode: 'ai_video',
    clip_duration: clipDur,
    aspect_ratio: job.aspect_ratio || '9:16',
    target_duration: targetDuration,
    tts_text: ttsText || '',
    total_duration: totalDuration
  });
  let oh = 0x811c9dc5;
  for (let i = 0; i < hashInput.length; i++) {
    oh ^= hashInput.charCodeAt(i);
    oh = Math.imul(oh, 0x01000193);
  }
  outputHash = (oh >>> 0).toString(16).padStart(8, '0');
}

return [{
  json: {
    ...job,
    production_mode: 'ai_video',
    kling_video_url: videoUrls[0],
    kling_video_urls: videoUrls,
    tts_audio_url: tts.audioUrl,
    tts_duration: tts.duration,
    tts_text: ttsText,
    tts_subtitles: subtitles,
    scene_results: videoUrls.map((u, i) => ({ index: i, video_url: u, model: 'kling-3.0/video', duration: hasScenes ? parseInt(scenes[i]?.duration_sec) || perClipSec : perClipSec, prompt: hasScenes ? scenes[i]?.prompt : undefined })),
    total_scenes: clipCount,
    total_duration: totalDuration,
    all_images: allImages,
    direct_image_urls: directImages,
    bgm_mode: bgmMode,
    sfx_mode: sfxMode,
    bgm_url: job.bgm_url || '',
    sfx_file_url: sfxFileUrl,
    image_order: imageOrder,
    length_gate_status: lengthGateStatus,
    length_gate_log: lengthGateLog,
    clip_count: clipCount,
    clip_duration_mode: isAutoClip ? 'auto' : 'fixed',
    actual_clip_duration: clipDur,
    per_clip_sec: perClipSec,
    scene_duration: sceneDuration,
    total_duration_source: totalDurationSource,
    sfx_timings: sfxTimings,
    target_duration: targetDuration,
    verify_mode: verifyMode,
    output_hash: outputHash
  }
}];

