// Prompt Lock 불일치 — 최신 prompt_p1 기준 재생성
const job = $input.first().json;

// prompt_hash를 현재 해시로 갱신
const p1 = (job.prompt_p1 || '').trim();
let currentHash = '';
if (p1) {
  let h = 0x811c9dc5;
  for (let i = 0; i < p1.length; i++) {
    h ^= p1.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  currentHash = (h >>> 0).toString(16).padStart(8, '0');
  currentHash += '-' + p1.length + '-' + p1.substring(0, 4).split('').map(c => c.charCodeAt(0).toString(16)).join('');
}

// 최신 prompt_p1 기준으로 prompt_to_engine 재조립
