const dbResult = $input.first().json;
const dbHash = dbResult.prompt_hash || '';
const currentHash = processResult.prompt_hash || processResult.prompt_hash_current || '';

// 불일치 시 에러 (이전 생성 무효)
if (dbHash && currentHash && dbHash !== currentHash) {
  throw new Error('PROMPT_LOCK_CHANGED: 렌더 직전 prompt가 변경됨. 재시도 필요.');
}

return [{ json: { ...processResult } }];

// AO 프롬프트 조립기 — Last-Edit Priority + Prompt Lock (재생성 연결)
const job = $input.first().json;

// mark-processing RETURNING * 에서 최신 DB 값이 이미 전달됨
const p1 = (job.prompt_p1 || '').trim();

// files 파싱
let files = [];
try {
  files = typeof job.clips === 'string' ? JSON.parse(job.clips) : (job.clips || []);
} catch(e) { files = []; }

// FNV-1a 해시 함수
function fnvHash(text) {
  let h = 0x811c9dc5;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  const hex = (h >>> 0).toString(16).padStart(8, '0');
  return hex + '-' + text.length + '-' + text.substring(0, 4).split('').map(c => c.charCodeAt(0).toString(16)).join('');
}

// Prompt Lock: prompt_hash 비교
const storedHash = job.prompt_hash || '';
const currentHash = p1 ? fnvHash(p1) : '';
const promptLockValid = !storedHash || storedHash === currentHash;

// Prompt Lock 불일치 시: 최신 prompt_p1 기준으로 재생성
// mark-processing RETURNING * 에서 이미 최신 DB 값이므로 현재 p1이 최신
// 저장된 해시만 현재 해시로 갱신 (DB UPDATE는 아래 플래그로 후속 처리)
let promptHashToUse = storedHash;
let promptLockAction = 'none';
if (!promptLockValid && p1) {
  // 기존 계획 폐기 → 현재 prompt_p1 기준으로 재조립
  promptHashToUse = currentHash;
  promptLockAction = 'regenerated';
}

// Last-Edit Priority: prompt_p1을 그대로 사용 (슬롯 치환 없음)
const finalPrompt = p1;

// 파일 분석 결과 수집
const analysisParts = [];
files.forEach((f, i) => {
  if (f.vision_analysis) analysisParts.push(`[Image ${i+1}: ${f.vision_analysis}]`);
  if (f.video_analysis) analysisParts.push(`[Video ${i+1}: ${f.video_analysis}]`);
});

// P1이 없으면 topic 기반 자동 프롬프트 (fallback)
let basePrompt = finalPrompt;
if (!p1) {
  const autoParts = [];
  if (job.topic) autoParts.push(`Create a cinematic video about: ${job.topic}`);
  if (job.keywords) autoParts.push(`Keywords: ${job.keywords}`);
  if (job.category) autoParts.push(`Category: ${job.category}`);
  basePrompt = autoParts.join('. ') + '. High quality, smooth motion, professional cinematography.';
}

const promptWithAnalysis = analysisParts.length > 0
  ? analysisParts.join('\n') + '\n' + basePrompt
  : basePrompt;

// generated_images 파싱
let generatedImages = [];
try {
  generatedImages = typeof job.generated_images === 'string' ? JSON.parse(job.generated_images) : (job.generated_images || []);
} catch(e) { generatedImages = []; }

// Length Gate: target_duration 설정
const targetDuration = job.duration || null;
const maxDuration = targetDuration ? targetDuration + 1 : null;
const strictMode = job.strict_mode === true;
const verifyMode = job.verify_mode === true;

// Prompt Lock 불일치 시 prompt_hash 갱신 (DB UPDATE)
if (promptLockAction === 'regenerated') {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://76.13.182.180:8080/v1/toolkit/echo',
      headers: { 'Content-Type': 'application/json' },
      body: { message: `prompt_lock_regenerated: job=${job.id}, old=${storedHash}, new=${currentHash}` },
      json: true,
      timeout: 5000
    });
  } catch(e) { /* 로깅 실패 무시 */ }
}

return [{
