function escSingle(t) {
  if (!t) return '';
  return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
    .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
    .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
    .replace(/\[/g,'\\[').replace(/\]/g,'\\]').replace(/\n/g,' ');
}
function escMulti(t) {
  if (!t) return '';
  return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
    .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
    .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
    .replace(/\[/g,'\\[').replace(/\]/g,'\\]');
}
function wrap(t, max) {
  if (!t || t.replace(/\s+/g,'').length <= max) return t || '';
  const mid = Math.floor(t.length / 2);
  let best = -1, minD = t.length;
  for (let i = 1; i < t.length - 1; i++) {
    if (t[i] === ' ' && Math.abs(i - mid) < minD) { minD = Math.abs(i - mid); best = i; }
  }
  if (best > 0) return t.substring(0, best).trim() + '\n' + t.substring(best).trim();
  return t.substring(0, max) + '\n' + t.substring(max);
}
function wrapTitle(t, max) {
  if (!t || t.length <= max) return t || '';
  const mid = Math.floor(t.length / 2);
  let best = -1, minD = t.length;
  for (let i = 0; i < t.length; i++) {
    if (t[i] === ',' && Math.abs(i+1-mid) < minD) { minD = Math.abs(i+1-mid); best = i+1; }
  }
  if (best === -1) {
    for (let i = 1; i < t.length-1; i++) {
      if (t[i] === ' ' && Math.abs(i-mid) < minD) { minD = Math.abs(i-mid); best = i; }
    }
  }
  if (best > 0) return t.substring(0, best).trim() + '\n' + t.substring(best).trim();
  return t.substring(0, max) + '\n' + t.substring(max);
}

