      aspect_ratio: job.aspect_ratio || '9:16',
      target_duration: targetDuration,
      tts_text: ttsText || '',
      total_duration: audioDuration
    });
    let oh = 0x811c9dc5;
    for (let i = 0; i < hashInput.length; i++) {
      oh ^= hashInput.charCodeAt(i);
      oh = Math.imul(oh, 0x01000193);
    }
    outputHash = (oh >>> 0).toString(16).padStart(8, '0');
  }

  return [{
    json: {
      ...job,
      production_mode: 'slideshow',
      slide_image_urls: allImages,
      tts_audio_url: tts.audioUrl,
      tts_duration: audioDuration,
