      enable_bgm: job.enable_bgm || false,
      enable_sfx: job.enable_sfx || false,
      bgm_url: job.bgm_url || '',
      length_gate_status: lengthGateStatus,
      target_duration: targetDuration,
      max_duration: maxDuration,
      verify_mode: verifyMode,
      output_hash: outputHash
    }
  }];
}

