// === Length Gate ===
const targetDuration = job.target_duration || job.duration || null;
const strictMode = job.strict_mode === true;
let lengthGateStatus = 'no_gate';
let clipCount = 1;
let lengthGateLog = '';

if (targetDuration) {
  // 통과 기준: strict=target±1초, soft=target-3초 이상
  const maxDuration = strictMode ? targetDuration + 1 : targetDuration + 1;
  const minDuration = strictMode ? targetDuration - 1 : targetDuration - 3;

  if (totalDuration >= minDuration && totalDuration <= maxDuration) {
    lengthGateStatus = 'pass';
  } else if (totalDuration < minDuration) {
    // 너무 짧음 → clip_count 보정 (영상 클립 반복으로 채움)
    clipCount = Math.ceil(targetDuration / Math.max(totalDuration, 1));
    const adjustedDuration = totalDuration * clipCount;
    if (adjustedDuration >= minDuration) {
      lengthGateStatus = 'corrected_short';
      totalDuration = Math.min(adjustedDuration, targetDuration);
      lengthGateLog = `짧음 보정: ${clipCount}클립, ${adjustedDuration.toFixed(1)}s`;
    } else if (strictMode) {
      lengthGateStatus = 'blocked_short';
      throw new Error(`LENGTH_GATE_BLOCKED: ${totalDuration.toFixed(1)}s < min ${minDuration}s (strict_mode)`);
    } else {
      lengthGateStatus = 'under_soft';
      lengthGateLog = `목표 미달 soft: ${totalDuration.toFixed(1)}s < ${minDuration}s`;
    }
  } else {
    // 너무 김 → clip_count 재계산
    clipCount = Math.ceil(totalDuration / targetDuration);
    const adjustedDuration = totalDuration / clipCount;
    if (adjustedDuration <= maxDuration && adjustedDuration >= minDuration) {
      lengthGateStatus = 'corrected_long';
      totalDuration = adjustedDuration;
      lengthGateLog = `김 보정: ${clipCount}클립, ${adjustedDuration.toFixed(1)}s`;
    } else if (strictMode) {
      lengthGateStatus = 'blocked_long';
      throw new Error(`LENGTH_GATE_BLOCKED: ${totalDuration.toFixed(1)}s > max ${maxDuration}s (strict_mode)`);
    } else {
      lengthGateStatus = 'over_soft';
      lengthGateLog = `목표 초과 soft: ${totalDuration.toFixed(1)}s > ${maxDuration}s`;
    }
  }
}

// === Verify Mode: output_hash 생성 ===
