}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      productionId: productionId,
      status: status,
      error: result.last_error || $('에러 캡처').first().json?.error_message || null,
      retryCount: result.retry_count || 0,
      jobId: jobId
    },
    json: true
  });
  return [{ json: { ...result, callback_sent: true } }];
} catch(e) {
  return [{ json: { ...result, callback_sent: false, callback_error: e.message } }];
}

const job = $input.first().json;
const productionId = job.production_id;
const callbackUrl = $env.WEBAPP_CALLBACK_URL;
if (!productionId || !callbackUrl) return [{ json: job }];
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: { productionId, status: 'processing', jobId: job.id },
    json: true
  });
} catch(e) {}
return [{ json: job }];

const job = $input.first().json;
const productionId = job.production_id;
const callbackUrl = $env.WEBAPP_CALLBACK_URL;
if (!productionId || !callbackUrl) return [{ json: job }];
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: { productionId, status: 'rendering', jobId: job.id },
    json: true
  });
} catch(e) {}
return [{ json: job }];

const job = $input.first().json;
const productionId = job.production_id;
const callbackUrl = $env.WEBAPP_CALLBACK_URL;

// verify_mode: output_hash를 job_logs에 기록
if (job.verify_mode === true && job.output_hash) {
  try {
    const logDetail = JSON.stringify({
      output_hash: job.output_hash,
      length_gate_status: job.length_gate_status || 'no_gate',
      total_duration: job.total_duration || 0,
      target_duration: job.target_duration || 0,
      prompt_hash: job.prompt_hash || '',
      clip_count: job.clip_count || 1
    });
    // job_logs INSERT via n8n postgres - use internal API
    // Note: this runs as a callback, the actual INSERT is handled by the DB node pattern
    // Store for downstream logging
    job._verify_log = logDetail;
  } catch(e) {}
}

if (!productionId || !callbackUrl) return [{ json: job }];
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      productionId,
      status: 'generated',
      jobId: job.id,
      videoUrl: job.rendered_video_url || null,
      renderedVideoUrl: job.rendered_video_url || null,
      output_hash: job.output_hash || null,
      length_gate_status: job.length_gate_status || null
    },
    json: true
  });
} catch(e) {}
return [{ json: job }];

// Prompt Lock 불일치 — 최신 prompt_p1 기준 재생성
const job = $input.first().json;

// prompt_hash를 현재 해시로 갱신
const p1 = (job.prompt_p1 || '').trim();
let currentHash = '';
if (p1) {
  let h = 0x811c9dc5;
  for (let i = 0; i < p1.length; i++) {
    h ^= p1.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  currentHash = (h >>> 0).toString(16).padStart(8, '0');
  currentHash += '-' + p1.length + '-' + p1.substring(0, 4).split('').map(c => c.charCodeAt(0).toString(16)).join('');
}

// 최신 prompt_p1 기준으로 prompt_to_engine 재조립
const analysisParts = [];
const files = job.files || [];
files.forEach((f, i) => {
  if (f.vision_analysis) analysisParts.push(`[Image ${i+1}: ${f.vision_analysis}]`);
  if (f.video_analysis) analysisParts.push(`[Video ${i+1}: ${f.video_analysis}]`);
});

let basePrompt = p1;
if (!p1) {
  const autoParts = [];
  if (job.topic) autoParts.push(`Create a cinematic video about: ${job.topic}`);
  if (job.keywords) autoParts.push(`Keywords: ${job.keywords}`);
  basePrompt = autoParts.join('. ') + '. High quality, smooth motion.';
}

const promptWithAnalysis = analysisParts.length > 0
  ? analysisParts.join('\n') + '\n' + basePrompt
  : basePrompt;

return [{
  json: {
    ...job,
    prompt_to_engine: promptWithAnalysis,
    prompt_hash: currentHash,
    prompt_hash_current: currentHash,
    prompt_lock_valid: true,
    prompt_lock_action: 'regenerated',
    assembled_at: new Date().toISOString()
  }
}];

// 렌더 직전 prompt_hash 재확인
const processResult = $('멀티씬 순차 처리').first().json;
const dbResult = $input.first().json;
const dbHash = dbResult.prompt_hash || '';
const currentHash = processResult.prompt_hash || processResult.prompt_hash_current || '';

// 불일치 시 에러 (이전 생성 무효)
if (dbHash && currentHash && dbHash !== currentHash) {
  throw new Error('PROMPT_LOCK_CHANGED: 렌더 직전 prompt가 변경됨. 재시도 필요.');
}

return [{ json: { ...processResult } }];
